// Geteilte Form-Primitives für Auth-Screens. Bewusst klein gehalten —
// in Sprint 1 noch keine Library wie react-hook-form, das kommt mit den
// Game-Screens (Sprint 4+).

import type { ButtonHTMLAttributes, InputHTMLAttributes } from 'react'

export function Field({
  label,
  error,
  ...inputProps
}: { label: string; error?: string } & InputHTMLAttributes<HTMLInputElement>) {
  return (
    <label style={{ display: 'flex', flexDirection: 'column', gap: 6, marginBottom: '0.9rem' }}>
      <span style={{ fontSize: '0.8rem', fontWeight: 600, letterSpacing: '0.3px', opacity: 0.75 }}>
        {label}
      </span>
      <input
        {...inputProps}
        style={{
          padding: '0.7rem 0.85rem',
          fontSize: '1rem',
          border: `1.5px solid ${error ? 'var(--red)' : 'rgba(0,0,0,0.15)'}`,
          borderRadius: 10,
          background: 'var(--white)',
          outline: 'none',
          fontFamily: 'inherit',
          ...((inputProps.style as object) ?? {})
        }}
      />
      {error && (
        <span style={{ fontSize: '0.75rem', color: 'var(--red)' }}>{error}</span>
      )}
    </label>
  )
}

type ButtonProps = ButtonHTMLAttributes<HTMLButtonElement> & {
  variant?: 'primary' | 'ghost'
}

export function Button({ variant = 'primary', children, ...rest }: ButtonProps) {
  const isPrimary = variant === 'primary'
  return (
    <button
      {...rest}
      style={{
        width: '100%',
        padding: '0.8rem 1rem',
        fontSize: '1rem',
        fontWeight: 600,
        letterSpacing: '0.5px',
        borderRadius: 10,
        cursor: rest.disabled ? 'not-allowed' : 'pointer',
        opacity: rest.disabled ? 0.5 : 1,
        transition: 'transform 80ms ease-out, box-shadow 120ms ease-out',
        background: isPrimary ? 'var(--red)' : 'transparent',
        color: isPrimary ? 'var(--cream)' : 'var(--red)',
        border: isPrimary ? 'none' : '2px solid var(--red)',
        ...((rest.style as object) ?? {})
      }}
    >
      {children}
    </button>
  )
}

export function FormError({ children }: { children: React.ReactNode }) {
  if (!children) return null
  return (
    <div
      role="alert"
      style={{
        padding: '0.6rem 0.8rem',
        background: 'rgba(200, 21, 10, 0.08)',
        border: '1px solid var(--red)',
        borderRadius: 8,
        color: 'var(--red)',
        fontSize: '0.85rem',
        marginBottom: '0.9rem'
      }}
    >
      {children}
    </div>
  )
}
