import { useState } from 'react'

// Kleiner Latein-Toggle laut CLAUDE.md §6.1 — auf der Card-Rückseite, blendet
// `latin_term` ein wenn vorhanden. Nur auf Karten mit non-null latin_term.

export function LatinToggle({ latinTerm }: { latinTerm: string | null | undefined }) {
  const [show, setShow] = useState(false)
  if (!latinTerm) return null

  return (
    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6 }}>
      <button
        type="button"
        onClick={(e) => {
          e.stopPropagation()
          setShow((s) => !s)
        }}
        aria-pressed={show}
        title="Lateinischer Fachbegriff"
        style={{
          background: 'none',
          border: '1.5px solid var(--green)',
          color: 'var(--green)',
          width: 32,
          height: 32,
          borderRadius: 999,
          fontSize: '1rem',
          cursor: 'pointer',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          padding: 0,
          opacity: show ? 1 : 0.6,
          transition: 'opacity 120ms'
        }}
      >
        🏛️
      </button>
      {show && (
        <span
          style={{
            fontFamily: 'Georgia, serif',
            fontStyle: 'italic',
            fontSize: '0.95rem',
            color: 'var(--green)',
            textAlign: 'center'
          }}
        >
          {latinTerm}
        </span>
      )}
    </div>
  )
}
