import { supabase } from './supabase'

// Schaltet ein Achievement frei (idempotent — Duplikat-Inserts werden über
// den Composite-Primary-Key (user_id, achievement_id) abgefangen).
// Vergibt zusätzlich die XP-Belohnung als Eintrag in xp_events und
// erhöht profiles.app_xp.virag um den Wert.
//
// In Sprint 8 wird daraus ein zentraler Achievement-Engine mit Toast/Overlay —
// hier nur die DB-Mechanik. Die UI-Feedback-Schicht ist dem Caller überlassen.
export async function unlockAchievement(code: string) {
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return { ok: false as const, error: 'not authenticated' }

  // 1) Achievement-Definition laden
  const { data: ach, error: achErr } = await supabase
    .from('achievements')
    .select('id, xp_reward')
    .eq('code', code)
    .single()
  if (achErr || !ach) return { ok: false as const, error: achErr?.message ?? 'achievement not found' }

  const achievementId = ach.id as number
  const xpReward = (ach.xp_reward as number) ?? 0

  // 2) user_achievements einfügen — Duplicate-Konflikt ist OK (idempotent)
  const { error: linkErr } = await supabase
    .from('user_achievements')
    .insert({ user_id: user.id, achievement_id: achievementId })

  if (linkErr) {
    if (linkErr.code === '23505' || linkErr.message.toLowerCase().includes('duplicate')) {
      return { ok: true as const, alreadyUnlocked: true, xp: 0 }
    }
    return { ok: false as const, error: linkErr.message }
  }

  // 3) XP gutschreiben — Event + JSONB-Update in profiles
  if (xpReward > 0) {
    await Promise.all([
      supabase.from('xp_events').insert({
        user_id: user.id,
        app: 'virag',
        mode: 'meta',
        xp_amount: xpReward,
        source: `achievement:${code}`
      }),
      // app_xp.virag = coalesce(app_xp->>'virag', 0)::int + xpReward
      // Postgres-side via RPC wäre sauberer; im MVP bleibt's clientseitig
      // mit kurzem Read-Modify-Write. Race-Conditions sind hier vernachlässigbar
      // (Achievements sind seltene Single-User-Events).
      bumpViragXp(user.id, xpReward)
    ])
  }

  return { ok: true as const, alreadyUnlocked: false, xp: xpReward }
}

async function bumpViragXp(userId: string, amount: number) {
  const { data: profile } = await supabase
    .from('profiles')
    .select('app_xp')
    .eq('id', userId)
    .single()

  const current = (profile?.app_xp as Record<string, number> | null) ?? {}
  const next = { ...current, virag: (current.virag ?? 0) + amount }

  await supabase.from('profiles').update({ app_xp: next }).eq('id', userId)
}
