import { create } from 'zustand'
import type { Session, User } from '@supabase/supabase-js'
import { supabase } from '@/lib/supabase'

type AuthState = {
  session: Session | null
  user: User | null
  loading: boolean
  /** true bis zum ersten Auth-Check (verhindert Splash-Flicker auf ProtectedRoute) */
  hydrated: boolean
  setSession: (s: Session | null) => void
  signOut: () => Promise<void>
}

export const useAuthStore = create<AuthState>((set) => ({
  session: null,
  user: null,
  loading: false,
  hydrated: false,
  setSession: (session) =>
    set({ session, user: session?.user ?? null, hydrated: true }),
  signOut: async () => {
    await supabase.auth.signOut()
    set({ session: null, user: null })
  }
}))

// Initial Session laden + auf Änderungen hören. Wird einmal beim App-Start
// aufgerufen (siehe main.tsx).
export function initAuthListener() {
  supabase.auth.getSession().then(({ data }) => {
    useAuthStore.getState().setSession(data.session)
  })

  supabase.auth.onAuthStateChange((_event, session) => {
    useAuthStore.getState().setSession(session)
  })
}
