import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { motion } from 'framer-motion'
import { useAuthStore } from '@/store/useAuthStore'
import { useFilterStore } from '@/store/useFilterStore'
import { loadFilteredVocab, pickRandom, shuffle, type VocabCard } from '@/lib/vocab'
import { awardXp } from '@/lib/xp'
import { fireFlowerConfetti } from '@/lib/confetti'
import { Header } from '@/components/Header'
import { XPToast, type XpToastData } from '@/components/XPToast'
import { ScoreScreen } from '@/components/ScoreScreen'

// Modus 2 — Wörterpaare / Matching laut CLAUDE.md §6.2.
//   - Pool: 50 zufällige aus vocab_medical, 6 pro Runde
//   - 6 HU links, 6 DE rechts (random shuffle innerhalb)
//   - Tap-Tap-Matching: korrekt = grün + Confetti, falsch = rotes Aufblitzen
//   - XP: 10 pro Match (= 60 XP pro perfekte Runde)
//   - Score-Screen am Ende mit "nochmal"-Button

const ROUND_SIZE = 6
const POOL_SIZE = 50

type Side = 'hu' | 'de'
type SelKey = `${Side}:${number}`

export default function Matching() {
  const { user } = useAuthStore()
  const filter = useFilterStore()
  const navigate = useNavigate()

  const [pool, setPool] = useState<VocabCard[] | null>(null)
  const [round, setRound] = useState<VocabCard[]>([])
  const [huOrder, setHuOrder] = useState<number[]>([])
  const [deOrder, setDeOrder] = useState<number[]>([])
  const [matched, setMatched] = useState<Set<number>>(new Set())
  const [selected, setSelected] = useState<SelKey | null>(null)
  const [wrong, setWrong] = useState<SelKey | null>(null)
  const [matches, setMatches] = useState(0)
  const [misses, setMisses] = useState(0)
  const [done, setDone] = useState(false)
  const [toast, setToast] = useState<XpToastData | null>(null)
  const [error, setError] = useState<string | null>(null)

  // Pool laden
  useEffect(() => {
    let cancelled = false
    async function load() {
      try {
        const cards = await loadFilteredVocab(filter, user?.id ?? null)
        if (cancelled) return
        if (cards.length < ROUND_SIZE) {
          setError(`Zu wenige Karten gefunden (${cards.length}). Andere Filter probieren.`)
          setPool([])
          return
        }
        setPool(pickRandom(cards, POOL_SIZE))
        setError(null)
      } catch (e) {
        setError(String((e as Error).message ?? e))
      }
    }
    void load()
    return () => { cancelled = true }
  }, [user, filter.category, filter.wordClass, filter.difficulty, filter.mastery])

  // Neue Runde wenn Pool da
  useEffect(() => {
    if (!pool || pool.length === 0) return
    startRound()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pool])

  function startRound() {
    if (!pool) return
    const next = pickRandom(pool, ROUND_SIZE)
    setRound(next)
    setHuOrder(shuffle(next.map((_, i) => i)))
    setDeOrder(shuffle(next.map((_, i) => i)))
    setMatched(new Set())
    setSelected(null)
    setWrong(null)
    setMatches(0)
    setMisses(0)
    setDone(false)
  }

  function handleClick(side: Side, index: number) {
    if (matched.has(index) || wrong || done) return

    const key: SelKey = `${side}:${index}`

    if (!selected) {
      setSelected(key)
      return
    }
    if (selected === key) {
      setSelected(null)
      return
    }

    const [selSide, selIdxStr] = selected.split(':') as [Side, string]
    const selIdx = parseInt(selIdxStr, 10)

    if (selSide === side) {
      // gleiche Spalte → einfach umschalten
      setSelected(key)
      return
    }

    // Match-Check: beide Seiten zeigen auf gleichen Card-Index
    if (selIdx === index) {
      const newMatched = new Set(matched)
      newMatched.add(index)
      setMatched(newMatched)
      setSelected(null)
      setMatches((m) => m + 1)
      fireFlowerConfetti()

      if (newMatched.size === round.length) {
        // Runde fertig → XP-Vergabe
        const totalMatches = newMatched.size
        const baseXp = totalMatches * 10
        void (async () => {
          const result = await awardXp({ baseAmount: baseXp, source: 'matching_round_complete', mode: 'medical' })
          if (result) setToast({ id: Date.now(), ...result })
        })()
        setDone(true)
      }
    } else {
      // Falscher Match → rotes Aufblitzen, dann deselect
      setWrong(key)
      setMisses((m) => m + 1)
      setTimeout(() => {
        setWrong(null)
        setSelected(null)
      }, 450)
    }
  }

  useEffect(() => {
    if (!toast) return
    const t = setTimeout(() => setToast(null), 1200)
    return () => clearTimeout(t)
  }, [toast])

  if (error) {
    return (
      <Wrapper>
        <Status>⚠ {error}</Status>
        <button onClick={() => navigate('/home')} style={btnGhost}>Zurück</button>
      </Wrapper>
    )
  }

  if (pool === null) {
    return <Wrapper><Status>Karten werden geladen…</Status></Wrapper>
  }

  if (done) {
    const xpEarned = matches * 10
    return (
      <ScoreScreen
        emoji="🌺"
        title="Runde geschafft!"
        subtitle={misses === 0 ? 'Perfekt — kein Fehlversuch.' : `${misses} Fehlversuche`}
        stats={[
          { label: 'Paare', value: matches, highlight: true },
          { label: 'Fehlversuche', value: misses }
        ]}
        totalXp={xpEarned}
        primaryAction={{ label: 'Nochmal', onClick: startRound }}
        secondaryAction={{ label: 'Zurück zu Home', onClick: () => navigate('/home') }}
      />
    )
  }

  return (
    <Wrapper>
      <div
        style={{
          width: '100%',
          maxWidth: 480,
          display: 'flex',
          justifyContent: 'space-between',
          fontSize: '0.85rem',
          opacity: 0.7,
          marginBottom: '0.4rem'
        }}
      >
        <span>Matches: {matches} / {round.length}</span>
        <span>Fehler: {misses}</span>
      </div>

      <div
        style={{
          width: '100%',
          maxWidth: 480,
          display: 'grid',
          gridTemplateColumns: '1fr 1fr',
          gap: 10
        }}
      >
        <Column>
          {huOrder.map((i) => {
            const c = round[i]
            const key: SelKey = `hu:${i}`
            return (
              <Tile
                key={key}
                text={c.hungarian}
                onClick={() => handleClick('hu', i)}
                state={tileState(key, selected, wrong, matched.has(i))}
                serif
              />
            )
          })}
        </Column>
        <Column>
          {deOrder.map((i) => {
            const c = round[i]
            const key: SelKey = `de:${i}`
            return (
              <Tile
                key={key}
                text={c.german}
                onClick={() => handleClick('de', i)}
                state={tileState(key, selected, wrong, matched.has(i))}
              />
            )
          })}
        </Column>
      </div>

      <button onClick={() => navigate('/home')} style={{ ...btnGhost, marginTop: '1.5rem' }}>
        Sitzung abbrechen
      </button>

      <XPToast toast={toast} />
    </Wrapper>
  )
}

type TileState = 'idle' | 'selected' | 'wrong' | 'matched'

function tileState(key: SelKey, selected: SelKey | null, wrong: SelKey | null, isMatched: boolean): TileState {
  if (isMatched) return 'matched'
  if (wrong === key) return 'wrong'
  if (selected === key) return 'selected'
  return 'idle'
}

function Tile({ text, onClick, state, serif }: { text: string; onClick: () => void; state: TileState; serif?: boolean }) {
  const colors = {
    idle: { bg: 'var(--white)', border: 'rgba(0,0,0,0.15)', color: 'inherit' },
    selected: { bg: 'var(--white)', border: 'var(--orange)', color: 'var(--orange)' },
    wrong: { bg: 'rgba(200,21,10,0.12)', border: 'var(--red)', color: 'var(--red)' },
    matched: { bg: 'rgba(62,90,10,0.12)', border: 'var(--green)', color: 'var(--green)' }
  }[state]

  return (
    <motion.button
      onClick={onClick}
      disabled={state === 'matched'}
      animate={state === 'wrong' ? { x: [0, -4, 4, -4, 4, 0] } : {}}
      transition={{ duration: 0.4 }}
      style={{
        background: colors.bg,
        border: `2px solid ${colors.border}`,
        color: colors.color,
        padding: '0.85rem 0.6rem',
        borderRadius: 12,
        fontFamily: serif ? 'Georgia, serif' : 'inherit',
        fontWeight: serif ? 700 : 500,
        fontSize: '0.95rem',
        cursor: state === 'matched' ? 'default' : 'pointer',
        minHeight: 56,
        opacity: state === 'matched' ? 0.55 : 1,
        transition: 'all 150ms',
        textAlign: 'center'
      }}
    >
      {text}
    </motion.button>
  )
}

function Column({ children }: { children: React.ReactNode }) {
  return <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>{children}</div>
}

function Wrapper({ children }: { children: React.ReactNode }) {
  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--cream)' }}>
      <Header />
      <main
        style={{
          flex: 1,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          padding: '1.5rem 1rem 3rem'
        }}
      >
        {children}
      </main>
    </div>
  )
}

function Status({ children }: { children: React.ReactNode }) {
  return <div style={{ opacity: 0.55, fontSize: '0.95rem', marginTop: '20vh' }}>{children}</div>
}

const btnGhost: React.CSSProperties = {
  background: 'none',
  border: '1.5px solid rgba(0,0,0,0.15)',
  padding: '0.45rem 0.9rem',
  borderRadius: 8,
  fontFamily: 'inherit',
  fontSize: '0.8rem',
  cursor: 'pointer',
  opacity: 0.65
}
