import { supabase } from './supabase'

// XP-Vergabe für Virág laut CLAUDE.md §8.
//
// Verhalten:
//   1. Streak-Multiplikator anwenden (×1.0..×2.0 je nach current_streak)
//   2. xp_event INSERT (für Stats / Heatmap)
//   3. profiles.app_xp.virag JSONB-Update
//
// Race-Conditions sind theoretisch möglich beim Read-Modify-Write von app_xp,
// im MVP aber tolerabel (selten parallele Writes pro User).
// In Sprint 9 ersetzen durch Postgres-RPC `add_virag_xp(p_amount int)`.

export type Mode = 'medical' | 'everyday' | 'meta'

export function streakMultiplier(streak: number): number {
  if (streak >= 100) return 2.0
  if (streak >= 30) return 1.5
  if (streak >= 7) return 1.2
  return 1.0
}

export type AwardResult = {
  base: number
  multiplier: number
  awarded: number
  streak: number
}

export async function awardXp(opts: {
  baseAmount: number
  source: string
  mode?: Mode
}): Promise<AwardResult | null> {
  const { baseAmount, source, mode = 'medical' } = opts

  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return null

  // 1) Profile lesen (für Streak + bisheriges app_xp)
  const { data: profile } = await supabase
    .from('profiles')
    .select('current_streak, app_xp')
    .eq('id', user.id)
    .single()

  const streak = (profile?.current_streak as number) ?? 0
  const multiplier = streakMultiplier(streak)
  const awarded = Math.round(baseAmount * multiplier)

  // 2) xp_event Insert (parallel zum profiles-Update)
  // 3) profiles.app_xp.virag bumpen
  const currentApp = (profile?.app_xp as Record<string, number> | null) ?? {}
  const nextApp = { ...currentApp, virag: (currentApp.virag ?? 0) + awarded }

  await Promise.all([
    supabase.from('xp_events').insert({
      user_id: user.id,
      app: 'virag',
      mode,
      xp_amount: awarded,
      source,
      metadata: { base: baseAmount, multiplier }
    }),
    supabase.from('profiles').update({ app_xp: nextApp }).eq('id', user.id)
  ])

  return { base: baseAmount, multiplier, awarded, streak }
}
