// SM-2 Algorithmus für SRS — pure functions, ohne DB-Zugriff. Macht
// Unit-Tests trivial (Sprint 4 hat noch kein Test-Setup; kommt mit Sprint 9).
//
// Referenz: Piotr Wozniak, SuperMemo SM-2 (1985).
//
// Quality-Skala: 0..5
//   0..2 = falsch / vergessen → repetition reset
//   3..5 = richtig
//
// 4-Button-UI-Mapping (CLAUDE.md §6.1):
//   Again = 0
//   Hard  = 3
//   Good  = 4
//   Easy  = 5

export type Quality = 0 | 1 | 2 | 3 | 4 | 5

export type Rating = 'again' | 'hard' | 'good' | 'easy'

export const RATING_TO_QUALITY: Record<Rating, Quality> = {
  again: 0,
  hard: 3,
  good: 4,
  easy: 5
}

export const RATING_XP: Record<Rating, number> = {
  again: 2,
  hard: 5,
  good: 10,
  easy: 15
}

export type SrsState = {
  ease_factor: number
  interval_days: number
  repetitions: number
}

export type SrsUpdate = SrsState & { next_review_at: string }

const DAY_MS = 86_400_000

/**
 * Wendet SM-2 auf einen aktuellen Card-State an und gibt den nächsten State
 * + ISO-Timestamp für next_review_at zurück.
 *
 * Initial-State (für Karten ohne SRS-Row): { ease_factor: 2.5, interval_days: 1, repetitions: 0 }
 */
export function applySm2(state: SrsState, quality: Quality): SrsUpdate {
  let { ease_factor, interval_days, repetitions } = state

  // Ease Factor anpassen — gilt sowohl bei richtig als auch falsch.
  // Untergrenze 1.3 (Standard SM-2).
  ease_factor = Math.max(
    1.3,
    ease_factor + (0.1 - (5 - quality) * (0.08 + (5 - quality) * 0.02))
  )

  if (quality < 3) {
    // Vergessen → Repetitionen zurücksetzen, morgen nochmal
    repetitions = 0
    interval_days = 1
  } else {
    repetitions += 1
    if (repetitions === 1) {
      interval_days = 1
    } else if (repetitions === 2) {
      interval_days = 6
    } else {
      interval_days = Math.round(interval_days * ease_factor)
    }
  }

  const next_review_at = new Date(Date.now() + interval_days * DAY_MS).toISOString()
  // ease_factor auf 2 Nachkommastellen normalisieren (DB-Spalte ist numeric(4,2))
  ease_factor = Math.round(ease_factor * 100) / 100

  return { ease_factor, interval_days, repetitions, next_review_at }
}

export const INITIAL_SRS: SrsState = {
  ease_factor: 2.5,
  interval_days: 1,
  repetitions: 0
}
