import { useEffect, useRef, useState, type FormEvent } from 'react'
import { useNavigate, useSearchParams } from 'react-router-dom'
import { motion } from 'framer-motion'
import { useAuthStore } from '@/store/useAuthStore'
import { loadVerbs, recordVerbAttempt, TENSE_LABEL, PERSON_LABEL, PERSON_DE, hasUsableTense, pickRandomPerson, type Tense, type Person, type VerbRow } from '@/lib/verbs'
import { levenshtein, normalizeForCompare } from '@/lib/levenshtein'
import { awardXp } from '@/lib/xp'
import { fireFlowerConfetti } from '@/lib/confetti'
import { Header } from '@/components/Header'
import { DiacriticKeyboard } from '@/components/DiacriticKeyboard'
import { XPToast, type XpToastData } from '@/components/XPToast'
import { ScoreScreen } from '@/components/ScoreScreen'

// 7a — Konjugation tippen (CLAUDE.md §6.7)
//   Anzeige: Lemma + Person + Tempus → User tippt Form
//   +12 XP exakt, +6 XP 1-Zeichen-off, sonst 0

const ROUND_SIZE = 8

type Question = { verb: VerbRow; tense: Tense; person: Person; expected: string }

export default function Conjugate() {
  const { user } = useAuthStore()
  const navigate = useNavigate()
  const [params] = useSearchParams()
  const tense = (params.get('tense') ?? 'present_indefinite') as Tense

  const [verbs, setVerbs] = useState<VerbRow[] | null>(null)
  const [round, setRound] = useState<Question[]>([])
  const [step, setStep] = useState(0)
  const [input, setInput] = useState('')
  const [verdict, setVerdict] = useState<'pending' | 'exact' | 'one_off' | 'fail'>('pending')
  const [stats, setStats] = useState({ exact: 0, oneOff: 0, fail: 0, totalXp: 0, mastered: [] as string[] })
  const [done, setDone] = useState(false)
  const [toast, setToast] = useState<XpToastData | null>(null)
  const [error, setError] = useState<string | null>(null)
  const inputRef = useRef<HTMLInputElement | null>(null)

  useEffect(() => {
    let cancelled = false
    async function load() {
      try {
        const v = await loadVerbs()
        if (cancelled) return
        const usable = v.filter((x) => hasUsableTense(x, tense))
        if (usable.length === 0) {
          setError(`Keine Verben mit ${TENSE_LABEL[tense]}-Konjugation vorhanden.`)
          return
        }
        setVerbs(usable)
        startRound(usable)
      } catch (e) {
        setError(String((e as Error).message ?? e))
      }
    }
    void load()
    return () => { cancelled = true }
  }, [tense])

  function startRound(pool: VerbRow[]) {
    const qs: Question[] = []
    while (qs.length < ROUND_SIZE) {
      const v = pool[Math.floor(Math.random() * pool.length)]
      const p = pickRandomPerson(v, tense)
      if (!p) continue
      const expected = v.conjugations![tense][p]!
      qs.push({ verb: v, tense, person: p, expected })
    }
    setRound(qs)
    setStep(0)
    setInput('')
    setVerdict('pending')
    setStats({ exact: 0, oneOff: 0, fail: 0, totalXp: 0, mastered: [] })
    setDone(false)
    requestAnimationFrame(() => inputRef.current?.focus())
  }

  const current = round[step]

  async function handleSubmit(e?: FormEvent) {
    e?.preventDefault()
    if (!current || verdict !== 'pending' || !input.trim() || !user) return
    const dist = levenshtein(normalizeForCompare(input), normalizeForCompare(current.expected))
    const isExact = dist === 0
    const status = dist === 0 ? 'exact' : dist === 1 ? 'one_off' : 'fail'
    const xp = status === 'exact' ? 12 : status === 'one_off' ? 6 : 0
    setVerdict(status)
    if (isExact) fireFlowerConfetti()

    if (xp > 0) {
      void awardXp({ baseAmount: xp, source: `verb_conjugate_${status}`, mode: 'medical' })
        .then((r) => r && setToast({ id: Date.now(), ...r }))
    }
    void recordVerbAttempt(user.id, current.verb.id, current.tense, isExact).then((r) => {
      if (r.justMastered) {
        setStats((s) => ({ ...s, mastered: [...s.mastered, `${current.verb.infinitive} (${TENSE_LABEL[current.tense]})`] }))
        void awardXp({ baseAmount: 75, source: 'verb_mastered', mode: 'medical' })
      }
    })
    setStats((s) => ({
      ...s,
      exact: s.exact + (status === 'exact' ? 1 : 0),
      oneOff: s.oneOff + (status === 'one_off' ? 1 : 0),
      fail: s.fail + (status === 'fail' ? 1 : 0),
      totalXp: s.totalXp + xp
    }))
  }

  function handleNext() {
    if (step + 1 >= round.length) { setDone(true); return }
    setStep(step + 1)
    setInput('')
    setVerdict('pending')
    requestAnimationFrame(() => inputRef.current?.focus())
  }

  useEffect(() => { if (toast) { const t = setTimeout(() => setToast(null), 1200); return () => clearTimeout(t) } }, [toast])

  if (error) return <Wrapper><Status>⚠ {error}</Status><Back navigate={navigate} /></Wrapper>
  if (!verbs || !current) return <Wrapper><Status>Wird geladen…</Status></Wrapper>
  if (done) {
    return (
      <ScoreScreen
        emoji={stats.mastered.length > 0 ? '🏆' : '⚡'}
        title={`${stats.exact} / ${ROUND_SIZE} exakt`}
        subtitle={stats.mastered.length > 0 ? `Neu gemeistert: ${stats.mastered.join(', ')} (+75 XP/Tempus)` : undefined}
        stats={[
          { label: '✅ Exakt (×12)', value: stats.exact, highlight: true },
          { label: '⚠️ 1 Zeichen (×6)', value: stats.oneOff },
          { label: '❌ Daneben', value: stats.fail }
        ]}
        totalXp={stats.totalXp + stats.mastered.length * 75}
        primaryAction={{ label: 'Nochmal', onClick: () => verbs && startRound(verbs) }}
        secondaryAction={{ label: 'Zurück', onClick: () => navigate('/learn/medical/verb-trainer') }}
      />
    )
  }

  const verdictColor = verdict === 'exact' ? 'var(--green)' : verdict === 'fail' ? 'var(--red)' : verdict === 'one_off' ? 'var(--orange)' : 'rgba(0,0,0,0.15)'

  return (
    <Wrapper>
      <div style={{ width: '100%', maxWidth: 480, fontSize: '0.85rem', opacity: 0.65, marginBottom: '0.4rem' }}>
        {step + 1} / {round.length} · {TENSE_LABEL[tense]}
      </div>
      <div style={{ width: '100%', maxWidth: 480, background: 'var(--white)', border: '2px solid var(--red)', borderRadius: 14, padding: '1.5rem 1rem', textAlign: 'center', boxShadow: 'var(--shadow-card)' }}>
        <div style={{ fontSize: '0.75rem', opacity: 0.55, letterSpacing: '0.5px', marginBottom: 6 }}>
          {PERSON_DE[current.person]} · {PERSON_LABEL[current.person]}
        </div>
        <div className="hu-vocab" style={{ color: 'var(--red)', fontSize: '2rem' }}>
          {current.verb.infinitive}
        </div>
        <div style={{ fontSize: '0.85rem', opacity: 0.6, fontStyle: 'italic', marginTop: 4 }}>{current.verb.infinitive_de}</div>
      </div>

      <form onSubmit={handleSubmit} style={{ width: '100%', maxWidth: 480, marginTop: '1rem', display: 'flex', flexDirection: 'column', gap: 10 }}>
        <input
          ref={inputRef}
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          disabled={verdict !== 'pending'}
          autoComplete="off" autoCorrect="off" autoCapitalize="off" spellCheck={false}
          placeholder="Konjugierte Form…"
          style={{ padding: '0.85rem 1rem', fontSize: '1.15rem', border: `2px solid ${verdictColor}`, borderRadius: 12, fontFamily: 'Georgia, serif', fontWeight: 600, background: 'var(--white)', outline: 'none' }}
        />
        <DiacriticKeyboard lang="hu" inputRef={inputRef} onChange={setInput} />

        {verdict === 'pending' ? (
          <button type="submit" disabled={!input.trim()} style={{ background: 'var(--red)', color: 'var(--cream)', border: 'none', padding: '0.8rem', borderRadius: 10, fontWeight: 700, fontSize: '1rem', fontFamily: 'inherit', cursor: !input.trim() ? 'default' : 'pointer', opacity: !input.trim() ? 0.5 : 1 }}>
            Prüfen
          </button>
        ) : (
          <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} style={{ background: 'var(--white)', border: `2px solid ${verdictColor}`, borderRadius: 12, padding: '0.85rem', textAlign: 'center' }}>
            <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, color: verdictColor, marginBottom: 4 }}>
              {verdict === 'exact' && '✅ Exakt!'}
              {verdict === 'one_off' && '⚠️ Fast — 1 Zeichen daneben'}
              {verdict === 'fail' && '❌ Daneben'}
            </div>
            {verdict !== 'exact' && (
              <div style={{ fontSize: '0.9rem' }}>
                <span style={{ opacity: 0.6 }}>Korrekt: </span>
                <b style={{ fontFamily: 'Georgia, serif', color: 'var(--green)' }}>{current.expected}</b>
              </div>
            )}
            <button onClick={handleNext} autoFocus style={{ marginTop: '0.7rem', background: verdictColor, color: 'var(--cream)', border: 'none', padding: '0.55rem 1.3rem', borderRadius: 8, fontWeight: 700, fontFamily: 'inherit', cursor: 'pointer' }}>
              {step + 1 >= round.length ? 'Ergebnis' : 'Weiter'}
            </button>
          </motion.div>
        )}
      </form>

      <Back navigate={navigate} />
      <XPToast toast={toast} />
    </Wrapper>
  )
}

function Wrapper({ children }: { children: React.ReactNode }) {
  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--cream)' }}>
      <Header />
      <main style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '1.5rem 1rem 3rem' }}>{children}</main>
    </div>
  )
}
function Status({ children }: { children: React.ReactNode }) { return <div style={{ opacity: 0.55, marginTop: '20vh' }}>{children}</div> }
function Back({ navigate }: { navigate: ReturnType<typeof useNavigate> }) {
  return <button onClick={() => navigate('/learn/medical/verb-trainer')} style={{ marginTop: '1.5rem', background: 'none', border: '1.5px solid rgba(0,0,0,0.15)', padding: '0.45rem 0.9rem', borderRadius: 8, fontFamily: 'inherit', fontSize: '0.8rem', cursor: 'pointer', opacity: 0.65 }}>Sitzung abbrechen</button>
}
