import { useEffect, useMemo, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { motion } from 'framer-motion'
import { useAuthStore } from '@/store/useAuthStore'
import { useFilterStore } from '@/store/useFilterStore'
import { loadFilteredVocab, pickRandom, shuffle, type VocabCard } from '@/lib/vocab'
import { awardXp } from '@/lib/xp'
import { Header } from '@/components/Header'
import { XPToast, type XpToastData } from '@/components/XPToast'
import { ScoreScreen } from '@/components/ScoreScreen'

// Modus 5 — Multiple Choice laut CLAUDE.md §6.5.
//   - 10 Fragen pro Runde
//   - HU-Wort + 4 DE-Optionen (1 korrekt, 3 Distraktoren AUS DERSELBEN KATEGORIE)
//   - XP: 10 korrekt, 2 falsch
//   - Score-Screen mit korrekt/falsch + Total-XP

const ROUND_QUESTIONS = 10
const XP_CORRECT = 10
const XP_WRONG = 2

type Question = {
  card: VocabCard
  options: string[]
  correctIndex: number
}

export default function Quiz() {
  const { user } = useAuthStore()
  const filter = useFilterStore()
  const navigate = useNavigate()

  const [pool, setPool] = useState<VocabCard[] | null>(null)
  const [questions, setQuestions] = useState<Question[]>([])
  const [step, setStep] = useState(0)
  const [picked, setPicked] = useState<number | null>(null)
  const [correct, setCorrect] = useState(0)
  const [wrong, setWrong] = useState(0)
  const [done, setDone] = useState(false)
  const [toast, setToast] = useState<XpToastData | null>(null)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false
    async function load() {
      try {
        const cards = await loadFilteredVocab(filter, user?.id ?? null)
        if (cancelled) return
        if (cards.length < 4) {
          setError(`Zu wenige Karten gefunden (${cards.length}). Andere Filter probieren.`)
          return
        }
        setPool(cards)
        setQuestions(buildQuestions(cards, ROUND_QUESTIONS))
        setStep(0)
        setPicked(null)
        setCorrect(0)
        setWrong(0)
        setDone(false)
      } catch (e) {
        setError(String((e as Error).message ?? e))
      }
    }
    void load()
    return () => { cancelled = true }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user, filter.category, filter.wordClass, filter.difficulty, filter.mastery])

  const totalXp = useMemo(() => correct * XP_CORRECT + wrong * XP_WRONG, [correct, wrong])

  function handlePick(idx: number) {
    if (picked !== null || done) return
    setPicked(idx)
    const isCorrect = idx === questions[step].correctIndex
    if (isCorrect) {
      setCorrect((c) => c + 1)
      void awardXp({ baseAmount: XP_CORRECT, source: 'quiz_correct', mode: 'medical' })
        .then((r) => r && setToast({ id: Date.now(), ...r }))
    } else {
      setWrong((w) => w + 1)
      void awardXp({ baseAmount: XP_WRONG, source: 'quiz_wrong', mode: 'medical' })
        .then((r) => r && setToast({ id: Date.now(), ...r }))
    }

    setTimeout(() => {
      if (step + 1 >= ROUND_QUESTIONS) {
        setDone(true)
      } else {
        setStep((s) => s + 1)
        setPicked(null)
      }
    }, 700)
  }

  useEffect(() => {
    if (!toast) return
    const t = setTimeout(() => setToast(null), 1200)
    return () => clearTimeout(t)
  }, [toast])

  function restart() {
    if (!pool) return
    setQuestions(buildQuestions(pool, ROUND_QUESTIONS))
    setStep(0)
    setPicked(null)
    setCorrect(0)
    setWrong(0)
    setDone(false)
  }

  if (error) return <Wrapper><Status>⚠ {error}</Status><button onClick={() => navigate('/home')} style={btnGhost}>Zurück</button></Wrapper>
  if (!pool || questions.length === 0) return <Wrapper><Status>Karten werden geladen…</Status></Wrapper>

  if (done) {
    return (
      <ScoreScreen
        emoji={correct >= 8 ? '🎉' : correct >= 5 ? '👍' : '🌱'}
        title={`${correct} / ${ROUND_QUESTIONS} richtig`}
        stats={[
          { label: 'Richtig (×10 XP)', value: correct, highlight: true },
          { label: 'Falsch (×2 XP)', value: wrong }
        ]}
        totalXp={totalXp}
        primaryAction={{ label: 'Nochmal', onClick: restart }}
        secondaryAction={{ label: 'Zurück zu Home', onClick: () => navigate('/home') }}
      />
    )
  }

  const q = questions[step]

  return (
    <Wrapper>
      <div style={{ width: '100%', maxWidth: 480, marginBottom: '0.7rem' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.85rem', opacity: 0.7 }}>
          <span>Frage {step + 1} / {ROUND_QUESTIONS}</span>
          <span>✓ {correct} · ✗ {wrong}</span>
        </div>
        <div style={{ height: 6, background: 'rgba(0,0,0,0.07)', borderRadius: 999, marginTop: 4, overflow: 'hidden' }}>
          <div
            style={{
              width: `${((step + (picked !== null ? 1 : 0)) / ROUND_QUESTIONS) * 100}%`,
              height: '100%',
              background: 'var(--header-stripe)',
              transition: 'width 200ms'
            }}
          />
        </div>
      </div>

      <div
        style={{
          width: '100%',
          maxWidth: 480,
          background: 'var(--white)',
          border: '2px solid var(--red)',
          borderRadius: 14,
          padding: '1.5rem 1rem',
          textAlign: 'center',
          boxShadow: 'var(--shadow-card)'
        }}
      >
        <div className="hu-vocab" style={{ color: 'var(--red)' }}>{q.card.hungarian}</div>
        {q.card.phonetic && (
          <div className="phonetic" style={{ marginTop: 4, fontSize: '0.9rem' }}>[{q.card.phonetic}]</div>
        )}
      </div>

      <div
        style={{
          width: '100%',
          maxWidth: 480,
          marginTop: '0.9rem',
          display: 'grid',
          gridTemplateColumns: '1fr 1fr',
          gap: 8
        }}
      >
        {q.options.map((opt, i) => {
          const isCorrectAnswer = picked !== null && i === q.correctIndex
          const isWrongPick = picked === i && i !== q.correctIndex
          const bg =
            isCorrectAnswer ? 'var(--green)' :
            isWrongPick ? 'var(--red)' : 'var(--white)'
          const color = isCorrectAnswer || isWrongPick ? 'var(--cream)' : 'inherit'
          const border = isCorrectAnswer ? 'var(--green)' : isWrongPick ? 'var(--red)' : 'rgba(0,0,0,0.15)'

          return (
            <motion.button
              key={i}
              animate={isWrongPick ? { x: [0, -5, 5, -5, 5, 0] } : {}}
              transition={{ duration: 0.35 }}
              onClick={() => handlePick(i)}
              disabled={picked !== null}
              style={{
                background: bg,
                color,
                border: `2px solid ${border}`,
                padding: '0.85rem',
                borderRadius: 12,
                fontFamily: 'inherit',
                fontSize: '0.95rem',
                fontWeight: 600,
                cursor: picked !== null ? 'default' : 'pointer',
                minHeight: 60,
                transition: 'background 150ms, border-color 150ms'
              }}
            >
              {opt}
            </motion.button>
          )
        })}
      </div>

      <button onClick={() => navigate('/home')} style={{ ...btnGhost, marginTop: '1.5rem' }}>
        Sitzung abbrechen
      </button>

      <XPToast toast={toast} />
    </Wrapper>
  )
}

function buildQuestions(pool: VocabCard[], n: number): Question[] {
  const cards = pickRandom(pool, n)
  return cards.map((card) => {
    // Distraktoren bevorzugt aus selber Kategorie
    const sameCategory = pool.filter(
      (c) => c.id !== card.id && c.category === card.category && c.german.toLowerCase() !== card.german.toLowerCase()
    )
    const fallback = pool.filter(
      (c) => c.id !== card.id && c.german.toLowerCase() !== card.german.toLowerCase()
    )
    const distractors = pickRandom(sameCategory.length >= 3 ? sameCategory : fallback, 3).map((c) => c.german)
    const options = shuffle([card.german, ...distractors])
    return { card, options, correctIndex: options.indexOf(card.german) }
  })
}

function Wrapper({ children }: { children: React.ReactNode }) {
  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--cream)' }}>
      <Header />
      <main style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '1.5rem 1rem 3rem' }}>
        {children}
      </main>
    </div>
  )
}

function Status({ children }: { children: React.ReactNode }) {
  return <div style={{ opacity: 0.55, fontSize: '0.95rem', marginTop: '20vh' }}>{children}</div>
}

const btnGhost: React.CSSProperties = {
  background: 'none',
  border: '1.5px solid rgba(0,0,0,0.15)',
  padding: '0.45rem 0.9rem',
  borderRadius: 8,
  fontFamily: 'inherit',
  fontSize: '0.8rem',
  cursor: 'pointer',
  opacity: 0.65
}
