import { useNavigate } from 'react-router-dom'
import { Header } from '@/components/Header'
import { BottomNav } from '@/components/BottomNav'
import { FilterBar } from '@/components/FilterBar'

// Lernen-Hub: alle 8 Spielmodi als 2-Spalten-Grid (Desktop) bzw. 1-Spalte (Mobile).
// Auf Home gibt's nur den horizontalen Scroll — diese Page ist die ausführliche
// Variante mit FilterBar oben, damit der User seine Vorauswahl sieht.

type Mode = {
  emoji: string
  title: string
  subtitle: string
  to: string
  available: boolean
  color: string
}

const MODES: Mode[] = [
  { emoji: '🃏',  title: 'Karteikarten',     subtitle: 'SRS · SM-2 · 4 Buttons',                to: '/learn/medical/flashcards',     available: true, color: 'var(--red)' },
  { emoji: '🔗',  title: 'Wörterpaare',      subtitle: '6 HU ↔ DE matchen',                     to: '/learn/medical/matching',       available: true, color: 'var(--green)' },
  { emoji: '🧩',  title: 'Satzreihenfolge',  subtitle: 'HU-Wörter in Reihenfolge bringen',      to: '/learn/medical/ordering',       available: true, color: 'var(--orange)' },
  { emoji: '⏱️', title: 'Speedround',       subtitle: '60s Timer · Combo · Highscore',         to: '/learn/medical/speedround',     available: true, color: 'var(--red)' },
  { emoji: '✅',  title: 'Multiple Choice',  subtitle: '10 Fragen · 4 Optionen',                to: '/learn/medical/quiz',           available: true, color: 'var(--lg)' },
  { emoji: '⌨️', title: 'Tippen',           subtitle: 'Aktiv schreiben · Production-Mastery',  to: '/learn/medical/vocab-trainer',   available: true, color: 'var(--green)' },
  { emoji: '⚡',  title: 'Verben',           subtitle: '5 Untermodi · pro Tempus',              to: '/learn/medical/verb-trainer',   available: true,  color: 'var(--yellow)' },
  { emoji: '🔁',  title: 'Synonyme',         subtitle: 'HU ↔ HU · 13 Paare',                    to: '/learn/medical/synonym-match',  available: false, color: 'var(--orange)' }
]

export default function Learn() {
  const navigate = useNavigate()

  return (
    <div style={{ minHeight: '100vh', background: 'var(--cream)', paddingBottom: 90 }}>
      <Header />
      <main className="app-container">
        <h1 className="app-name" style={{ color: 'var(--red)', margin: 0, fontSize: '1.45rem' }}>
          Lernen 📖
        </h1>
        <p style={{ opacity: 0.65, margin: 0, fontSize: '0.9rem' }}>
          Wähle einen Modus — die unten gesetzten Filter greifen in jedem Spiel.
        </p>

        <FilterBar />

        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))',
            gap: '0.7rem'
          }}
        >
          {MODES.map((m) => (
            <button
              key={m.to}
              disabled={!m.available}
              onClick={() => m.available && navigate(m.to)}
              style={{
                background: 'var(--white)',
                border: `2px solid ${m.color}`,
                borderRadius: 14,
                padding: '1rem',
                boxShadow: 'var(--shadow-card)',
                cursor: m.available ? 'pointer' : 'default',
                opacity: m.available ? 1 : 0.55,
                fontFamily: 'inherit',
                textAlign: 'left',
                display: 'grid',
                gridTemplateColumns: 'auto 1fr',
                gap: '0.85rem',
                alignItems: 'center',
                position: 'relative',
                minHeight: 80
              }}
            >
              <div style={{ fontSize: '2rem', lineHeight: 1 }} aria-hidden="true">{m.emoji}</div>
              <div>
                <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: '1rem', color: m.color }}>
                  {m.title}
                </div>
                <div style={{ fontSize: '0.78rem', opacity: 0.65, marginTop: 2 }}>{m.subtitle}</div>
              </div>
              {!m.available && (
                <div
                  style={{
                    position: 'absolute',
                    top: 8,
                    right: 10,
                    fontSize: '0.65rem',
                    background: 'var(--cream)',
                    border: '1px solid rgba(0,0,0,0.1)',
                    borderRadius: 6,
                    padding: '2px 6px',
                    opacity: 0.85
                  }}
                >
                  bald
                </div>
              )}
            </button>
          ))}
        </div>
      </main>
      <BottomNav />
    </div>
  )
}
