import { useEffect, useState } from 'react'
import { useAuthStore } from '@/store/useAuthStore'
import { supabase } from '@/lib/supabase'
import { Header } from '@/components/Header'
import { BottomNav } from '@/components/BottomNav'

// Stats — Sprint-3-Placeholder mit ein paar Live-Aggregaten.
// Vollständiger Stats-Screen (Heatmap, Recharts, Mastery-Heatmap pro Verb)
// kommt in Sprint 8.

type Aggregate = {
  totalXp: number
  totalReviews: number
  correctReviews: number
  productionMastered: number
  uniqueDays: number
}

export default function Stats() {
  const { user } = useAuthStore()
  const [agg, setAgg] = useState<Aggregate | null>(null)

  useEffect(() => {
    if (!user) return
    let cancelled = false

    async function load() {
      const [{ data: xp }, { data: srs }] = await Promise.all([
        supabase
          .from('xp_events')
          .select('xp_amount, created_at')
          .eq('user_id', user!.id)
          .eq('app', 'virag'),
        supabase
          .from('srs_medical')
          .select('total_reviews, correct_reviews, production_mastered_at')
          .eq('user_id', user!.id)
      ])

      if (cancelled) return

      const xpRows = (xp ?? []) as Array<{ xp_amount: number; created_at: string }>
      const totalXp = xpRows.reduce((s, r) => s + (r.xp_amount ?? 0), 0)
      const days = new Set(xpRows.map((r) => r.created_at.slice(0, 10)))

      const srsRows = (srs ?? []) as Array<{
        total_reviews: number
        correct_reviews: number
        production_mastered_at: string | null
      }>
      const totalReviews = srsRows.reduce((s, r) => s + (r.total_reviews ?? 0), 0)
      const correctReviews = srsRows.reduce((s, r) => s + (r.correct_reviews ?? 0), 0)
      const productionMastered = srsRows.filter((r) => r.production_mastered_at).length

      setAgg({ totalXp, totalReviews, correctReviews, productionMastered, uniqueDays: days.size })
    }

    void load()
    return () => { cancelled = true }
  }, [user])

  const correctPct = agg && agg.totalReviews > 0
    ? Math.round((agg.correctReviews / agg.totalReviews) * 100)
    : null

  return (
    <div style={{ minHeight: '100vh', background: 'var(--cream)', paddingBottom: 90 }}>
      <Header />
      <main className="app-container">
        <h1 className="app-name" style={{ color: 'var(--red)', margin: 0, fontSize: '1.45rem' }}>
          Statistiken 📊
        </h1>

        {!agg ? (
          <div style={{ opacity: 0.55, fontSize: '0.9rem', marginTop: '2rem' }}>Wird geladen…</div>
        ) : (
          <>
            <Card color="var(--red)">
              <Big>{agg.totalXp}</Big>
              <Label>Virág-XP gesamt</Label>
            </Card>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.7rem' }}>
              <Card color="var(--green)">
                <Big>{agg.totalReviews}</Big>
                <Label>Karten-Reviews</Label>
              </Card>
              <Card color="var(--orange)">
                <Big>{correctPct === null ? '—' : `${correctPct}%`}</Big>
                <Label>Richtig-Quote</Label>
              </Card>
              <Card color="var(--lg)">
                <Big>{agg.uniqueDays}</Big>
                <Label>aktive Tage</Label>
              </Card>
              <Card color="var(--yellow)">
                <Big>{agg.productionMastered}</Big>
                <Label>🏆 gemeistert</Label>
              </Card>
            </div>

            <div
              style={{
                background: 'var(--white)',
                border: '2px dashed rgba(0,0,0,0.15)',
                borderRadius: 12,
                padding: '1rem',
                fontSize: '0.85rem',
                opacity: 0.7,
                textAlign: 'center'
              }}
            >
              📈 Heatmap, Verlauf-Charts und Verb-Mastery-Tabelle kommen in Sprint 8.
            </div>
          </>
        )}
      </main>
      <BottomNav />
    </div>
  )
}

function Card({ color, children }: { color: string; children: React.ReactNode }) {
  return (
    <div
      style={{
        background: 'var(--white)',
        border: `2px solid ${color}`,
        borderRadius: 14,
        padding: '1rem',
        boxShadow: 'var(--shadow-card)',
        textAlign: 'center'
      }}
    >
      {children}
    </div>
  )
}

function Big({ children }: { children: React.ReactNode }) {
  return (
    <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: '1.8rem', color: 'var(--red)' }}>
      {children}
    </div>
  )
}

function Label({ children }: { children: React.ReactNode }) {
  return <div style={{ fontSize: '0.78rem', opacity: 0.7, marginTop: 2 }}>{children}</div>
}
