import { Navigate, Route, Routes } from 'react-router-dom'
import { useAuthStore } from './store/useAuthStore'
import { ProtectedRoute } from './components/ProtectedRoute'
import Splash from './screens/Splash'
import Demo from './screens/Demo'
import Login from './screens/auth/Login'
import Signup from './screens/auth/Signup'
import Forgot from './screens/auth/Forgot'
import Onboarding from './screens/Onboarding'
import Home from './screens/Home'
import Learn from './screens/Learn'
import Stats from './screens/Stats'
import Profile from './screens/Profile'
import Flashcards from './screens/learn/Flashcards'
import Matching from './screens/learn/Matching'
import Ordering from './screens/learn/Ordering'
import Speedround from './screens/learn/Speedround'
import Quiz from './screens/learn/Quiz'
import VocabTrainer from './screens/learn/VocabTrainer'
import VerbTrainer from './screens/learn/VerbTrainer'
import VerbConjugate from './screens/learn/verb/Conjugate'
import VerbMC from './screens/learn/verb/MultipleChoice'
import VerbReverse from './screens/learn/verb/Reverse'
import VerbTable from './screens/learn/verb/TableFill'
import VerbCloze from './screens/learn/verb/Cloze'

// Routing-Skelett laut CLAUDE.md §10. `:mode` ist im MVP fest auf 'medical' —
// die Route bleibt aber generisch (`/learn/:mode/...`), damit Phase 2 den
// Mode-Switcher ohne Refactor aktivieren kann.
//
// Splash auf "/" entscheidet anhand der Session: bei Login → /home, sonst /auth/login.
export default function App() {
  return (
    <Routes>
      <Route path="/" element={<RootRedirect />} />
      <Route path="/splash" element={<Splash />} />
      <Route path="/demo" element={<Demo />} />

      <Route path="/auth/login" element={<Login />} />
      <Route path="/auth/signup" element={<Signup />} />
      <Route path="/auth/forgot" element={<Forgot />} />

      <Route path="/onboarding" element={<ProtectedRoute><Onboarding /></ProtectedRoute>} />
      <Route path="/home"       element={<ProtectedRoute><Home /></ProtectedRoute>} />
      <Route path="/learn"      element={<ProtectedRoute><Learn /></ProtectedRoute>} />
      <Route path="/stats"      element={<ProtectedRoute><Stats /></ProtectedRoute>} />
      <Route path="/profile"    element={<ProtectedRoute><Profile /></ProtectedRoute>} />
      <Route path="/learn/medical/flashcards" element={<ProtectedRoute><Flashcards /></ProtectedRoute>} />
      <Route path="/learn/medical/matching"   element={<ProtectedRoute><Matching /></ProtectedRoute>} />
      <Route path="/learn/medical/ordering"   element={<ProtectedRoute><Ordering /></ProtectedRoute>} />
      <Route path="/learn/medical/speedround" element={<ProtectedRoute><Speedround /></ProtectedRoute>} />
      <Route path="/learn/medical/quiz"          element={<ProtectedRoute><Quiz /></ProtectedRoute>} />
      <Route path="/learn/medical/vocab-trainer"           element={<ProtectedRoute><VocabTrainer /></ProtectedRoute>} />
      <Route path="/learn/medical/verb-trainer"            element={<ProtectedRoute><VerbTrainer /></ProtectedRoute>} />
      <Route path="/learn/medical/verb-trainer/conjugate"  element={<ProtectedRoute><VerbConjugate /></ProtectedRoute>} />
      <Route path="/learn/medical/verb-trainer/mc"         element={<ProtectedRoute><VerbMC /></ProtectedRoute>} />
      <Route path="/learn/medical/verb-trainer/reverse"    element={<ProtectedRoute><VerbReverse /></ProtectedRoute>} />
      <Route path="/learn/medical/verb-trainer/table"      element={<ProtectedRoute><VerbTable /></ProtectedRoute>} />
      <Route path="/learn/medical/verb-trainer/cloze"      element={<ProtectedRoute><VerbCloze /></ProtectedRoute>} />

      {/* Catch-all → "/" lässt Splash + RootRedirect entscheiden */}
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  )
}

function RootRedirect() {
  const { session, hydrated } = useAuthStore()
  if (!hydrated) return <Splash />
  return <Navigate to={session ? '/home' : '/auth/login'} replace />
}
