import React from 'react'
import ReactDOM from 'react-dom/client'
import { BrowserRouter } from 'react-router-dom'
import App from './App'
import { initAuthListener } from './store/useAuthStore'
import './theme/colors.css'
import './theme/fonts.css'
import './theme/tailwind.css'

// Auth-State frühzeitig hydrieren — bevor React rendert, hört der Listener
// schon auf onAuthStateChange.
initAuthListener()

// basename matched vite.config.ts `base: '/magyarul/'`, damit React-Router
// im Production-Build unter nephron.at/magyarul/* sauber greift.
const basename = import.meta.env.BASE_URL.replace(/\/$/, '')

ReactDOM.createRoot(document.getElementById('root')!).render(
  <React.StrictMode>
    <BrowserRouter basename={basename}>
      <App />
    </BrowserRouter>
  </React.StrictMode>
)
