import { Header } from './Header'

// Gemeinsamer Score-Screen am Ende eines Modus-Durchlaufs.
// Wird von Matching, Ordering, Speedround, Quiz importiert — Form bleibt
// konsistent, jeweilige Stat-Liste ist flexibel.

export type ScoreStat = {
  label: string
  value: string | number
  highlight?: boolean
}

type Props = {
  emoji: string
  title: string
  subtitle?: string
  stats: ScoreStat[]
  totalXp: number
  primaryAction: { label: string; onClick: () => void }
  secondaryAction?: { label: string; onClick: () => void }
}

export function ScoreScreen({ emoji, title, subtitle, stats, totalXp, primaryAction, secondaryAction }: Props) {
  return (
    <div style={{ minHeight: '100vh', background: 'var(--cream)', display: 'flex', flexDirection: 'column' }}>
      <Header />
      <main
        style={{
          flex: 1,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          padding: '2rem 1.25rem 4rem',
          gap: '1.2rem',
          textAlign: 'center'
        }}
      >
        <div style={{ fontSize: '4rem', lineHeight: 1 }}>{emoji}</div>
        <h1 className="app-name" style={{ color: 'var(--green)', fontSize: '1.8rem', margin: 0 }}>
          {title}
        </h1>
        {subtitle && <p style={{ opacity: 0.75, margin: 0, maxWidth: 320 }}>{subtitle}</p>}

        <div
          style={{
            background: 'var(--white)',
            border: '2px solid var(--green)',
            borderRadius: 14,
            padding: '1.2rem',
            boxShadow: 'var(--shadow-card)',
            width: '100%',
            maxWidth: 360,
            display: 'flex',
            flexDirection: 'column',
            gap: '0.6rem'
          }}
        >
          {stats.map((s) => (
            <div
              key={s.label}
              style={{
                display: 'flex',
                justifyContent: 'space-between',
                fontSize: '0.95rem',
                fontWeight: s.highlight ? 700 : 500,
                color: s.highlight ? 'var(--red)' : 'inherit'
              }}
            >
              <span style={{ opacity: 0.75 }}>{s.label}</span>
              <span>{s.value}</span>
            </div>
          ))}
          <div style={{ height: 1, background: 'rgba(0,0,0,0.08)', margin: '0.3rem 0' }} />
          <div
            style={{
              display: 'flex',
              justifyContent: 'space-between',
              fontFamily: 'Georgia, serif',
              fontSize: '1.2rem',
              fontWeight: 700,
              color: 'var(--red)'
            }}
          >
            <span>Insgesamt</span>
            <span>+{totalXp} XP</span>
          </div>
        </div>

        <div style={{ width: '100%', maxWidth: 360, display: 'flex', flexDirection: 'column', gap: 8, marginTop: '0.5rem' }}>
          <button
            onClick={primaryAction.onClick}
            style={{
              background: 'var(--red)',
              color: 'var(--cream)',
              border: 'none',
              padding: '0.8rem 1rem',
              borderRadius: 10,
              fontWeight: 700,
              fontSize: '1rem',
              fontFamily: 'inherit',
              cursor: 'pointer'
            }}
          >
            {primaryAction.label}
          </button>
          {secondaryAction && (
            <button
              onClick={secondaryAction.onClick}
              style={{
                background: 'none',
                border: '2px solid var(--red)',
                color: 'var(--red)',
                padding: '0.7rem 1rem',
                borderRadius: 10,
                fontWeight: 600,
                fontSize: '0.95rem',
                fontFamily: 'inherit',
                cursor: 'pointer'
              }}
            >
              {secondaryAction.label}
            </button>
          )}
        </div>
      </main>
    </div>
  )
}
