import { useEffect, useRef, useState } from 'react'
import { useNavigate, useSearchParams } from 'react-router-dom'
import { motion } from 'framer-motion'
import { useAuthStore } from '@/store/useAuthStore'
import { loadVerbs, recordVerbAttempt, TENSE_LABEL, PERSONS, PERSON_LABEL, hasUsableTense, type Tense, type Person, type VerbRow } from '@/lib/verbs'
import { levenshtein, normalizeForCompare } from '@/lib/levenshtein'
import { awardXp } from '@/lib/xp'
import { fireFlowerConfetti } from '@/lib/confetti'
import { Header } from '@/components/Header'
import { XPToast, type XpToastData } from '@/components/XPToast'
import { ScoreScreen } from '@/components/ScoreScreen'

// 7d — Tempus-Tabelle ausfüllen: 6 Eingabefelder pro Verb.
//   +4 XP pro korrekte Zelle, +30 XP wenn alle 6 korrekt (CLAUDE.md §6.7)

const ROUND_VERBS = 3

type Question = { verb: VerbRow; tense: Tense; expected: Record<Person, string | null> }

export default function TableFill() {
  const { user } = useAuthStore()
  const navigate = useNavigate()
  const [params] = useSearchParams()
  const tense = (params.get('tense') ?? 'present_indefinite') as Tense

  const [verbs, setVerbs] = useState<VerbRow[] | null>(null)
  const [round, setRound] = useState<Question[]>([])
  const [step, setStep] = useState(0)
  const [inputs, setInputs] = useState<Record<Person, string>>({} as Record<Person, string>)
  const [verdict, setVerdict] = useState<Record<Person, boolean | null>>({} as Record<Person, boolean | null>)
  const [submitted, setSubmitted] = useState(false)
  const [stats, setStats] = useState({ cellCorrect: 0, perfectVerbs: 0, totalXp: 0, mastered: [] as string[] })
  const [done, setDone] = useState(false)
  const [toast, setToast] = useState<XpToastData | null>(null)
  const [error, setError] = useState<string | null>(null)
  const focusRef = useRef<HTMLInputElement | null>(null)

  useEffect(() => {
    let cancelled = false
    async function load() {
      try {
        const v = await loadVerbs()
        if (cancelled) return
        const usable = v.filter((x) => hasUsableTense(x, tense))
        if (usable.length < ROUND_VERBS) { setError(`Nur ${usable.length} Verben für ${TENSE_LABEL[tense]}.`); return }
        setVerbs(usable)
        startRound(usable)
      } catch (e) { setError(String((e as Error).message ?? e)) }
    }
    void load()
    return () => { cancelled = true }
  }, [tense])

  function startRound(pool: VerbRow[]) {
    const shuffled = [...pool].sort(() => Math.random() - 0.5).slice(0, ROUND_VERBS)
    const qs: Question[] = shuffled.map((v) => ({ verb: v, tense, expected: v.conjugations![tense] }))
    setRound(qs); setStep(0); resetInputs(); setSubmitted(false)
    setStats({ cellCorrect: 0, perfectVerbs: 0, totalXp: 0, mastered: [] }); setDone(false)
  }

  function resetInputs() {
    setInputs({ '1sg': '', '2sg': '', '3sg': '', '1pl': '', '2pl': '', '3pl': '' })
    setVerdict({} as Record<Person, boolean | null>)
  }

  async function handleCheck() {
    if (submitted || !user) return
    const q = round[step]
    setSubmitted(true)
    let cellCorrect = 0
    const v: Record<Person, boolean | null> = {} as Record<Person, boolean | null>
    for (const p of PERSONS) {
      const expected = q.expected[p]
      if (!expected) { v[p] = null; continue }
      const dist = levenshtein(normalizeForCompare(inputs[p] || ''), normalizeForCompare(expected))
      const ok = dist === 0
      v[p] = ok
      if (ok) cellCorrect += 1
    }
    setVerdict(v)
    const totalCells = PERSONS.filter((p) => q.expected[p] !== null).length
    const perfect = cellCorrect === totalCells
    const xp = cellCorrect * 4 + (perfect ? 30 : 0)
    if (perfect) fireFlowerConfetti()

    if (xp > 0) {
      void awardXp({ baseAmount: xp, source: perfect ? 'verb_table_perfect' : 'verb_table_partial', mode: 'medical' })
        .then((r) => r && setToast({ id: Date.now(), ...r }))
    }
    void recordVerbAttempt(user.id, q.verb.id, q.tense, perfect).then((r) => {
      if (r.justMastered) {
        setStats((s) => ({ ...s, mastered: [...s.mastered, `${q.verb.infinitive} (${TENSE_LABEL[q.tense]})`] }))
        void awardXp({ baseAmount: 75, source: 'verb_mastered', mode: 'medical' })
      }
    })
    setStats((s) => ({ ...s, cellCorrect: s.cellCorrect + cellCorrect, perfectVerbs: s.perfectVerbs + (perfect ? 1 : 0), totalXp: s.totalXp + xp }))
  }

  function handleNext() {
    if (step + 1 >= round.length) { setDone(true); return }
    setStep(step + 1); resetInputs(); setSubmitted(false); requestAnimationFrame(() => focusRef.current?.focus())
  }

  useEffect(() => { if (toast) { const t = setTimeout(() => setToast(null), 1200); return () => clearTimeout(t) } }, [toast])

  if (error) return <Wrap><Status>⚠ {error}</Status><Back nav={navigate} /></Wrap>
  if (!verbs || round.length === 0) return <Wrap><Status>Wird geladen…</Status></Wrap>
  if (done) {
    return (
      <ScoreScreen
        emoji={stats.perfectVerbs === ROUND_VERBS ? '🏆' : '🔢'}
        title={`${stats.perfectVerbs} / ${ROUND_VERBS} perfekte Tabellen`}
        subtitle={stats.mastered.length > 0 ? `Neu gemeistert: ${stats.mastered.join(', ')}` : undefined}
        stats={[
          { label: 'Zellen richtig (×4)', value: stats.cellCorrect, highlight: true },
          { label: 'Perfekte Tabelle (×30)', value: stats.perfectVerbs }
        ]}
        totalXp={stats.totalXp + stats.mastered.length * 75}
        primaryAction={{ label: 'Nochmal', onClick: () => verbs && startRound(verbs) }}
        secondaryAction={{ label: 'Zurück', onClick: () => navigate('/learn/medical/verb-trainer') }}
      />
    )
  }

  const q = round[step]

  return (
    <Wrap>
      <div style={{ width: '100%', maxWidth: 480, fontSize: '0.85rem', opacity: 0.65, marginBottom: '0.4rem' }}>
        Verb {step + 1} / {round.length} · {TENSE_LABEL[tense]}
      </div>
      <div style={{ width: '100%', maxWidth: 480, background: 'var(--white)', border: '2px solid var(--red)', borderRadius: 14, padding: '1.2rem 1rem', textAlign: 'center', boxShadow: 'var(--shadow-card)' }}>
        <div className="hu-vocab" style={{ color: 'var(--red)', fontSize: '1.7rem' }}>{q.verb.infinitive}</div>
        <div style={{ fontSize: '0.85rem', opacity: 0.6, marginTop: 4 }}>{q.verb.infinitive_de}</div>
      </div>

      <div style={{ width: '100%', maxWidth: 480, marginTop: '0.9rem', display: 'flex', flexDirection: 'column', gap: 6 }}>
        {PERSONS.map((p, idx) => {
          const expected = q.expected[p]
          const isUnused = expected === null
          const v = verdict[p]
          const border = v === true ? 'var(--green)' : v === false ? 'var(--red)' : 'rgba(0,0,0,0.15)'
          return (
            <div key={p} style={{ display: 'grid', gridTemplateColumns: '4rem 1fr', gap: 8, alignItems: 'center' }}>
              <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, opacity: 0.8 }}>{PERSON_LABEL[p]}</div>
              {isUnused ? (
                <div style={{ padding: '0.7rem 1rem', opacity: 0.4, fontStyle: 'italic' }}>– (defektiv)</div>
              ) : (
                <input
                  ref={idx === 0 ? focusRef : undefined}
                  type="text"
                  value={inputs[p]}
                  onChange={(e) => setInputs({ ...inputs, [p]: e.target.value })}
                  disabled={submitted}
                  autoComplete="off" autoCapitalize="off" spellCheck={false}
                  placeholder={submitted && v === false ? expected ?? '' : ''}
                  style={{ padding: '0.65rem 0.9rem', border: `2px solid ${border}`, borderRadius: 10, fontFamily: 'Georgia, serif', fontWeight: 600, fontSize: '0.95rem', background: submitted && v === false ? 'rgba(200,21,10,0.07)' : 'var(--white)', outline: 'none' }}
                />
              )}
            </div>
          )
        })}
      </div>

      {!submitted ? (
        <button onClick={handleCheck} style={{ marginTop: '1rem', background: 'var(--red)', color: 'var(--cream)', border: 'none', padding: '0.7rem 1.5rem', borderRadius: 10, fontWeight: 700, fontFamily: 'inherit', cursor: 'pointer' }}>
          Tabelle prüfen
        </button>
      ) : (
        <motion.button initial={{ opacity: 0 }} animate={{ opacity: 1 }} onClick={handleNext} autoFocus style={{ marginTop: '1rem', background: 'var(--green)', color: 'var(--cream)', border: 'none', padding: '0.7rem 1.5rem', borderRadius: 10, fontWeight: 700, fontFamily: 'inherit', cursor: 'pointer' }}>
          {step + 1 >= round.length ? 'Ergebnis' : 'Nächstes Verb'}
        </motion.button>
      )}
      <Back nav={navigate} />
      <XPToast toast={toast} />
    </Wrap>
  )
}

function Wrap({ children }: { children: React.ReactNode }) { return (<div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--cream)' }}><Header /><main style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '1.5rem 1rem 3rem' }}>{children}</main></div>) }
function Status({ children }: { children: React.ReactNode }) { return <div style={{ opacity: 0.55, marginTop: '20vh' }}>{children}</div> }
function Back({ nav }: { nav: ReturnType<typeof useNavigate> }) { return <button onClick={() => nav('/learn/medical/verb-trainer')} style={{ marginTop: '1.5rem', background: 'none', border: '1.5px solid rgba(0,0,0,0.15)', padding: '0.45rem 0.9rem', borderRadius: 8, fontFamily: 'inherit', fontSize: '0.8rem', cursor: 'pointer', opacity: 0.65 }}>Sitzung abbrechen</button> }
