import { useEffect, useState } from 'react'
import { useAuthStore } from '@/store/useAuthStore'
import { supabase } from '@/lib/supabase'
import { Header } from '@/components/Header'
import { BottomNav } from '@/components/BottomNav'
import { StreakBox } from '@/components/StreakBox'
import { FilterBar } from '@/components/FilterBar'
import { ThemeGrid } from '@/components/ThemeGrid'
import { GameModeScroll } from '@/components/GameModeScroll'

// Home laut CLAUDE.md §10 — Modus-Hub: Themen-Grid (Medical-Kategorien) +
// Spielmodi-Scroll. In Sprint 3 funktional mit echten DB-Daten:
//
//   - Profil-Kopf (Name, Rang, XP, Tagesziel-Progress)
//   - StreakBox (live update_streak RPC)
//   - FilterBar (global state)
//   - ThemeGrid (dynamische Counts aus vocab_medical)
//   - GameModeScroll (8 Modi, alle "bald" — Sprint 4 schaltet Flashcards frei)

type ProfileLite = {
  display_name: string | null
  rank: string | null
  level: number | null
  total_xp: number | null
  daily_goal_xp: number | null
  app_xp: Record<string, number> | null
}

export default function Home() {
  const { user, signOut } = useAuthStore()
  const [profile, setProfile] = useState<ProfileLite | null>(null)
  const [todayXp, setTodayXp] = useState<number>(0)

  useEffect(() => {
    if (!user) return
    let cancelled = false

    async function load() {
      const [{ data: p }, { data: events }] = await Promise.all([
        supabase
          .from('profiles')
          .select('display_name, rank, level, total_xp, daily_goal_xp, app_xp')
          .eq('id', user!.id)
          .single(),
        supabase
          .from('xp_events')
          .select('xp_amount')
          .eq('user_id', user!.id)
          .eq('app', 'virag')
          .gte('created_at', new Date(new Date().setHours(0, 0, 0, 0)).toISOString())
      ])

      if (cancelled) return
      setProfile(p as ProfileLite | null)
      const sum = (events ?? []).reduce(
        (acc, e) => acc + ((e as { xp_amount: number }).xp_amount ?? 0),
        0
      )
      setTodayXp(sum)
    }

    void load()
    return () => { cancelled = true }
  }, [user])

  const goal = profile?.daily_goal_xp ?? 100
  const progress = Math.min(100, Math.round((todayXp / goal) * 100))

  return (
    <div style={{ minHeight: '100vh', background: 'var(--cream)', paddingBottom: 90 }}>
      <Header />
      <main className="app-container">

        {/* Begrüßung + Tagesziel */}
        <section>
          <h1 className="app-name" style={{ color: 'var(--red)', margin: 0, fontSize: '1.45rem' }}>
            Szia, {profile?.display_name ?? user?.email?.split('@')[0] ?? '…'}!
          </h1>
          <div style={{ display: 'flex', alignItems: 'baseline', gap: 8, marginTop: 4 }}>
            <span style={{ fontSize: '0.9rem', opacity: 0.7 }}>
              {profile?.rank ?? 'Medikus I'} · Level {profile?.level ?? 1}
            </span>
            <span style={{ fontSize: '0.85rem', opacity: 0.55 }}>
              · {(profile?.app_xp?.virag ?? 0)} XP
            </span>
          </div>

          {/* Tagesziel-Progressbar */}
          <div style={{ marginTop: '0.85rem' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.78rem', opacity: 0.7, marginBottom: 4 }}>
              <span>Tagesziel</span>
              <span>{todayXp} / {goal} XP</span>
            </div>
            <div
              style={{
                height: 10,
                background: 'rgba(0,0,0,0.06)',
                borderRadius: 999,
                overflow: 'hidden'
              }}
            >
              <div
                style={{
                  height: '100%',
                  width: `${progress}%`,
                  background: progress >= 100 ? 'var(--green)' : 'var(--header-stripe)',
                  borderRadius: 999,
                  transition: 'width 400ms ease-out'
                }}
              />
            </div>
          </div>
        </section>

        <StreakBox />
        <FilterBar />

        {/* Themen */}
        <section>
          <h2
            style={{
              fontFamily: 'Georgia, serif',
              fontSize: '0.85rem',
              letterSpacing: '1px',
              textTransform: 'uppercase',
              opacity: 0.6,
              margin: '0 0 0.7rem 0'
            }}
          >
            Themen
          </h2>
          <ThemeGrid />
        </section>

        {/* Spielmodi */}
        <section>
          <h2
            style={{
              fontFamily: 'Georgia, serif',
              fontSize: '0.85rem',
              letterSpacing: '1px',
              textTransform: 'uppercase',
              opacity: 0.6,
              margin: '0 0 0.7rem 0'
            }}
          >
            Spielmodi
          </h2>
          <GameModeScroll />
        </section>

        {/* Footer-Aktionen */}
        <section style={{ marginTop: '0.5rem' }}>
          <button
            onClick={signOut}
            style={{
              background: 'none',
              border: '1.5px solid rgba(0,0,0,0.15)',
              padding: '0.5rem 0.9rem',
              borderRadius: 8,
              fontFamily: 'inherit',
              fontSize: '0.8rem',
              cursor: 'pointer',
              opacity: 0.7
            }}
          >
            Abmelden
          </button>
        </section>
      </main>
      <BottomNav />
    </div>
  )
}
