import confetti from 'canvas-confetti'

// Folk-Konfetti in Kalocsa-Farben — wird beim ersten 🌺-Moment im Onboarding
// und später bei Level-Ups / Achievement-Unlocks gefeuert.
const FOLK_COLORS = ['#C8150A', '#D96B10', '#C8A000', '#3E5A0A', '#6A9020']

export function fireFlowerConfetti() {
  const duration = 1200
  const end = Date.now() + duration

  ;(function frame() {
    confetti({
      particleCount: 4,
      angle: 60,
      spread: 65,
      origin: { x: 0, y: 0.7 },
      colors: FOLK_COLORS,
      scalar: 0.9
    })
    confetti({
      particleCount: 4,
      angle: 120,
      spread: 65,
      origin: { x: 1, y: 0.7 },
      colors: FOLK_COLORS,
      scalar: 0.9
    })
    if (Date.now() < end) requestAnimationFrame(frame)
  })()
}
