import { useEffect, useState } from 'react'
import { supabase } from '@/lib/supabase'
import { Header } from '@/components/Header'

// Sprint-1-Splash: Folk-Look mit Header (FolkDivider + Stripe), groß zentriert.
// In Sprint 2 ersetzt durch echten Auth-Redirect (→ /home oder /auth/login).
export default function Splash() {
  const [dbReachable, setDbReachable] = useState<'pending' | 'ok' | 'fail'>('pending')

  useEffect(() => {
    supabase.auth.getSession().then(({ error }) => {
      setDbReachable(error ? 'fail' : 'ok')
    })
  }, [])

  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--cream)' }}>
      <Header />

      <main
        style={{
          flex: 1,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          padding: '2rem',
          gap: '1.5rem'
        }}
      >
        <div style={{ fontSize: '5rem', lineHeight: 1 }} aria-hidden="true">🌺</div>
        <h1
          className="app-name"
          style={{
            fontSize: '3rem',
            color: 'var(--red)',
            margin: 0
          }}
        >
          VIRÁG
        </h1>
        <p style={{ opacity: 0.7, fontStyle: 'italic', margin: 0, fontSize: '1.1rem' }}>
          Magyarul tanulni
        </p>

        <div
          style={{
            marginTop: '2rem',
            fontSize: '0.85rem',
            opacity: 0.6,
            textAlign: 'center'
          }}
        >
          {dbReachable === 'pending' && 'Verbindung zur DB wird geprüft…'}
          {dbReachable === 'ok' && '✓ Supabase erreichbar'}
          {dbReachable === 'fail' && '⚠ Supabase nicht erreichbar — .env.local prüfen'}
        </div>
      </main>
    </div>
  )
}
