import { useEffect, useState } from 'react'
import { useAuthStore } from '@/store/useAuthStore'
import { supabase } from '@/lib/supabase'
import { Header } from '@/components/Header'
import { BottomNav } from '@/components/BottomNav'
import { Button } from '@/components/AuthFormPrimitives'

// Profile — Sprint-3-Placeholder.
// Vollständige Profile-Page mit Settings, Sprache-Toggle, Tagesziel-Editor,
// Soft-Delete-Flow kommt in Sprint 8.

type ProfileData = {
  display_name: string | null
  username: string | null
  avatar_emoji: string | null
  rank: string | null
  level: number | null
  current_streak: number | null
  longest_streak: number | null
  daily_goal_xp: number | null
  app_xp: Record<string, number> | null
}

export default function Profile() {
  const { user, signOut } = useAuthStore()
  const [profile, setProfile] = useState<ProfileData | null>(null)

  useEffect(() => {
    if (!user) return
    void supabase
      .from('profiles')
      .select('display_name, username, avatar_emoji, rank, level, current_streak, longest_streak, daily_goal_xp, app_xp')
      .eq('id', user.id)
      .single()
      .then(({ data }) => setProfile(data as ProfileData | null))
  }, [user])

  const viragXp = profile?.app_xp?.virag ?? 0

  return (
    <div style={{ minHeight: '100vh', background: 'var(--cream)', paddingBottom: 90 }}>
      <Header />
      <main className="app-container">
        <h1 className="app-name" style={{ color: 'var(--red)', margin: 0, fontSize: '1.45rem' }}>
          Profil 👤
        </h1>

        <div
          style={{
            background: 'var(--white)',
            border: '2px solid var(--red)',
            borderRadius: 14,
            padding: '1.5rem 1.25rem',
            boxShadow: 'var(--shadow-card)',
            display: 'flex',
            alignItems: 'center',
            gap: '1rem'
          }}
        >
          <div style={{ fontSize: '3rem' }}>{profile?.avatar_emoji ?? '🌺'}</div>
          <div style={{ flex: 1 }}>
            <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: '1.2rem', color: 'var(--red)' }}>
              {profile?.display_name ?? user?.email?.split('@')[0] ?? '…'}
            </div>
            <div style={{ fontSize: '0.85rem', opacity: 0.7, marginTop: 2 }}>
              {profile?.rank ?? 'Medikus I'} · Level {profile?.level ?? 1}
            </div>
            <div style={{ fontSize: '0.78rem', opacity: 0.55, marginTop: 2 }}>
              {user?.email}
            </div>
          </div>
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.7rem' }}>
          <InfoCard label="Virág-XP">{viragXp}</InfoCard>
          <InfoCard label="Tagesziel">{profile?.daily_goal_xp ?? 100} XP</InfoCard>
          <InfoCard label="Aktueller Streak">{profile?.current_streak ?? 0} Tage</InfoCard>
          <InfoCard label="Bestleistung">{profile?.longest_streak ?? 0} Tage</InfoCard>
        </div>

        <div
          style={{
            background: 'var(--white)',
            border: '2px dashed rgba(0,0,0,0.15)',
            borderRadius: 12,
            padding: '1rem',
            fontSize: '0.85rem',
            opacity: 0.7,
            textAlign: 'center'
          }}
        >
          ⚙️ Tagesziel ändern, Sprach-Toggle, Erinnerungs-Zeit, Account löschen — kommen in Sprint 8.
        </div>

        <div style={{ marginTop: '0.5rem', maxWidth: 280 }}>
          <Button variant="ghost" onClick={signOut}>Abmelden</Button>
        </div>
      </main>
      <BottomNav />
    </div>
  )
}

function InfoCard({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div
      style={{
        background: 'var(--white)',
        border: '2px solid var(--green)',
        borderRadius: 12,
        padding: '0.85rem 1rem',
        boxShadow: 'var(--shadow-card)'
      }}
    >
      <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: '1.3rem', color: 'var(--red)' }}>
        {children}
      </div>
      <div style={{ fontSize: '0.75rem', opacity: 0.65, marginTop: 2 }}>{label}</div>
    </div>
  )
}
